import React from 'react';
import { NavLink } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import './Sidebar.css';

const Sidebar = () => {
  const { user } = useAuth();
  const isAdmin = user?.role === 'admin';

  const customerNavItems = [
    { name: 'Dashboard', path: '/customer/dashboard' },
    { name: 'Transactions', path: '/customer/transactions' },
    { name: 'Returns', path: '/customer/returns' },
    { name: 'Messages', path: '/customer/messages' },
    { name: 'Profile', path: '/customer/profile' },
  ];

  const adminNavItems = [
    { name: 'Dashboard', path: '/admin/dashboard' },
    { name: 'Sensors', path: '/admin/sensors' },
    { name: 'Transactions', path: '/admin/transactions' },
    { name: 'Returns', path: '/admin/returns' },
    { name: 'Ratings', path: '/admin/ratings' },
    { name: 'Messages', path: '/admin/messages' },
    { name: 'Reports', path: '/admin/reports' },
    { name: 'Users', path: '/admin/users' },
  ];

  const navItems = isAdmin ? adminNavItems : customerNavItems;

  return (
    <aside className="sidebar">
      <div className="sidebar-header">
        <div className="sidebar-logo">
          <h2>AgriVend</h2>
          <p>{isAdmin ? 'Admin Panel' : 'Customer Portal'}</p>
        </div>
      </div>
      
      <nav className="sidebar-nav">
        {navItems.map((item) => (
          <NavLink
            key={item.path}
            to={item.path}
            className={({ isActive }) => 
              `sidebar-link ${isActive ? 'active' : ''}`
            }
          >
            <span className="link-text">{item.name}</span>
          </NavLink>
        ))}
      </nav>
    </aside>
  );
};

export default Sidebar;
